Actionscript.script:
onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{
		// 统一走搓招函数（支持DFA预输入）
		_root.技能函数.使用后撤步() || _root.技能函数.使用波动拳();
	}
}

_parent.攻击呐喊();
空手攻击搓招 = _root.技能函数.空手攻击搓招;
诛杀步可派生搓招 = _root.技能函数.诛杀步可派生搓招;
后撤步可派生搓招 = _root.技能函数.后撤步可派生搓招;
波动拳可派生搓招 = _root.技能函数.波动拳可派生搓招;
能量喷泉可派生搓招 = _root.技能函数.能量喷泉可派生搓招;
燃烧指节可派生搓招 = _root.技能函数.燃烧指节可派生搓招;
连环踢可派生搓招 = _root.技能函数.连环踢可派生搓招;
回旋踢可派生搓招 = _root.技能函数.回旋踢可派生搓招;

onClipEvent(load){
	子弹属性 = _root.子弹属性初始化(this);

	//以下部分只需要更改需要更改的属性,其余部分可注释掉
	子弹属性.声音 = "";
	子弹属性.霰弹值 = 3;
	子弹属性.子弹散射度 = 0;
	子弹属性.子弹种类 = "近战联弹";
	子弹属性.子弹威力 =  _parent._parent.空手攻击力 * 3;
	if (_parent._parent.被动技能.拳脚攻击 && _parent._parent.被动技能.拳脚攻击.启用)
	{
		子弹属性.子弹威力 *= 1 + _parent._parent.被动技能.拳脚攻击.等级 * 0.1;
	}
	if(_parent._parent.mp攻击加成){
		子弹属性.子弹威力 += _parent._parent.mp攻击加成;
	}
	子弹属性.子弹速度 = 0;
	子弹属性.Z轴攻击范围 = 70;
	子弹属性.击倒率 = 0.1;

	子弹属性.水平击退速度 = 20;
	子弹属性.血量上限击溃 = 0.01;
	//非常用
	/*
	子弹属性.垂直击退速度 = NaN;
	子弹属性.发射效果 = "";
	子弹属性.击中地图效果 = "火花".
	子弹属性.击中后子弹的效果 = "".
	子弹属性.命中率 = NaN.
	子弹属性.固伤 = NaN;
	子弹属性.百分比伤害 = NaN;

	子弹属性.防御粉碎 = NaN;
	*/
	子弹属性.区域定位area = this.area;
	/*
	//已初始化内容，通常不需要重复赋值，可注释掉
	子弹属性.发射者 = 子弹属性.发射者.
	子弹属性.shootX = 子弹属性.shootX;
	子弹属性.shootY = 子弹属性.shootY;
	子弹属性.shootZ = 子弹属性.shootZ;
	子弹属性.子弹敌我属性 = 子弹属性.子弹敌我属性;
	*/
	_root.子弹区域shoot传递(子弹属性);
}

onClipEvent(load){
	子弹属性 = _root.子弹属性初始化(this);

	//以下部分只需要更改需要更改的属性,其余部分可注释掉
	子弹属性.声音 = "";
	子弹属性.霰弹值 = 3;
	子弹属性.子弹散射度 = 0;
	子弹属性.子弹种类 = "近战联弹";
	子弹属性.子弹威力 =  _parent._parent.空手攻击力 * 3.5;
	if (_parent._parent.被动技能.拳脚攻击 && _parent._parent.被动技能.拳脚攻击.启用)
	{
		子弹属性.子弹威力 *= 1 + _parent._parent.被动技能.拳脚攻击.等级 * 0.1;
	}
	if(_parent._parent.mp攻击加成){
		子弹属性.子弹威力 += _parent._parent.mp攻击加成;
	}
	子弹属性.子弹速度 = 0;
	子弹属性.Z轴攻击范围 = 50;
	子弹属性.击倒率 = 0.1;

	子弹属性.水平击退速度 = 7;
	//非常用
	/*
	子弹属性.垂直击退速度 = NaN;
	子弹属性.发射效果 = "";
	子弹属性.击中地图效果 = "火花".
	子弹属性.击中后子弹的效果 = "".
	子弹属性.命中率 = NaN.
	子弹属性.固伤 = NaN;
	子弹属性.百分比伤害 = NaN;
	子弹属性.血量上限击溃 = NaN;
	子弹属性.防御粉碎 = NaN;
	*/
	子弹属性.区域定位area = this.area;
	/*
	//已初始化内容，通常不需要重复赋值，可注释掉
	子弹属性.发射者 = 子弹属性.发射者.
	子弹属性.shootX = 子弹属性.shootX;
	子弹属性.shootY = 子弹属性.shootY;
	子弹属性.shootZ = 子弹属性.shootZ;
	子弹属性.子弹敌我属性 = 子弹属性.子弹敌我属性;
	*/
	_root.子弹区域shoot传递(子弹属性);
}

onClipEvent (enterFrame) {
	if (_parent._parent._name == _root.控制目标)
	{	
		_parent.诛杀步可派生搓招();
		if(Key.isDown(_parent._parent.A键))
	{
    _root.空手攻击路由.跨容器标签跳转(_parent._parent, "破极拳1连招", "破极拳5连招");
	}

		/*if(Key.isDown(_parent._parent.A键))
		{_parent.gotoAndPlay("破极拳5连招");}*/
	}
}

onClipEvent(load){
   if(_root.是否阴影 == true)
   {
      this._visible = 1;
   }
   else
   {
      this._visible = 0;
   }
}
